import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, Package, X, Save, 
  Loader2, Search, TrendingDown, AlertCircle, CheckCircle2, 
  Box, Calendar, Tag, Layers 
} from 'lucide-react';
import GestionInventario from './GestionInventario';
import { generarNombreImagen } from '../utils/helpers';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showManual, setShowManual] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  
  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { cargarOfertas(); }, [localId]);

  const cargarOfertas = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => 
      o.producto.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.categoria.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [ofertas, searchTerm]);

  const stats = useMemo(() => ({
    total: ofertas.length,
    sinStock: ofertas.filter(o => o.stock <= 0).length,
    enOferta: ofertas.filter(o => o.precioViejo > o.precioNuevo).length
  }), [ofertas]);

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`,
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId
      };
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      setNuevoProd({ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: '' });
      cargarOfertas();
    } catch (err) { alert("Error al guardar"); }
  };

  return (
    <div style={containerStyle}>
      <div style={topBar}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}>
          <ArrowLeft size={18}/> Volver
        </button>
        <div style={badgeLocal}>ID Local: {localId.slice(-6)}</div>
      </div>

      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Panel de Inventario</h1>
          <p style={subtitleStyle}>Gestiona tus productos y ofertas activas</p>
        </div>
        <div style={actionsGroup}>
          <button onClick={() => setShowManual(true)} style={btnPlus}>
            <Plus size={20}/> Nueva Carga Manual
          </button>
        </div>
      </div>

      <div style={statsGrid}>
        <div style={statCard}>
          <Box color="#3b82f6" />
          <div><span style={statNum}>{stats.total}</span><p style={statLabel}>Productos</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #ef4444'}}>
          <AlertCircle color="#ef4444" />
          <div><span style={statNum}>{stats.sinStock}</span><p style={statLabel}>Sin Stock</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #10b981'}}>
          <TrendingDown color="#10b981" />
          <div><span style={statNum}>{stats.enOferta}</span><p style={statLabel}>En Oferta</p></div>
        </div>
      </div>

      <CargaMasiva localId={localId} onComplete={cargarOfertas} />

      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input 
          style={searchInput} 
          placeholder="Buscar por nombre, marca o categoría..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div style={gridStyle}>
        {loading ? (
          <div style={loaderContainer}><Loader2 className="animate-spin" size={40} color="#e67e22"/></div>
        ) : ofertasFiltradas.length > 0 ? (
          ofertasFiltradas.map(o => (
            <div key={o._id} style={{...itemCard, opacity: o.stock <= 0 ? 0.7 : 1}}>
              <div style={cardHeader}>
                <div style={o.stock <= 0 ? badgeStockOut : badgeStockIn}>
                   {o.stock <= 0 ? 'Sin Stock' : `Stock: ${o.stock}`}
                </div>
                {o.precioViejo > o.precioNuevo && <div style={badgePromo}>Oferta</div>}
              </div>

              <div style={cardBody}>
                <h4 style={prodName}>{o.producto}</h4>
                <div style={categoryTag}><Layers size={12}/> {o.categoria}</div>
                
                <div style={priceContainer}>
                  <span style={currentPrice}>${o.precioNuevo}</span>
                  {o.precioViejo && <span style={oldPrice}>${o.precioViejo}</span>}
                </div>
              </div>

              <div style={cardFooter}>
                <button style={btnActionEdit} title="Editar"><Edit size={16}/></button>
                <button 
                  style={btnActionDelete} 
                  title="Eliminar"
                  onClick={async () => {
                    if(window.confirm(`¿Eliminar ${o.producto}?`)) {
                      await axios.delete(`${API_URL}/api/ofertas/${o._id}`);
                      cargarOfertas();
                    }
                  }}
                ><Trash2 size={16}/></button>
              </div>
            </div>
          ))
        ) : (
          <div style={emptyState}>
            <Package size={60} color="#e2e8f0" />
            <p>No se encontraron productos</p>
          </div>
        )}
      </div>

      {showManual && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3 style={{margin:0}}>Registrar Producto</h3>
              <button onClick={() => setShowManual(false)} style={closeBtn}><X/></button>
            </div>
            <form onSubmit={handleCargaManual} style={formStyle}>
              <div style={inputGroup}>
                <label style={labelS}><Tag size={14}/> Tipo</label>
                <input style={inputS} placeholder="Ej: Aceite de Girasol" onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required />
              </div>
              <div style={inputGroup}>
                <label style={labelS}><CheckCircle2 size={14}/> Marca</label>
                <input style={inputS} placeholder="Ej: Natura" onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required />
              </div>
              <div style={inputGroup}>
                <label style={labelS}><Layers size={14}/> Contenido</label>
                <input style={inputS} placeholder="Ej: 900ml" onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required />
              </div>
              <div style={inputGroup}>
                <label style={labelS}><TrendingDown size={14}/> Precio Oferta</label>
                <input style={inputS} type="number" placeholder="0.00" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required />
              </div>
              <button type="submit" style={btnSave}><Save size={18}/> Guardar en Inventario</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

// --- ESTILOS CORREGIDOS ---
const containerStyle = { padding: '20px 40px', maxWidth: '1200px', margin: '0 auto', fontFamily: '"Inter", sans-serif', color: '#1e293b' };
const topBar = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const badgeLocal = { background: '#f1f5f9', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem', color: '#64748b', fontWeight: '600' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const actionsGroup = { display: 'flex', gap: '10px', alignItems: 'center' }; // Definido
const titleStyle = { fontSize: '2rem', fontWeight: '800', margin: 0, letterSpacing: '-0.5px' };
const subtitleStyle = { margin: 0, color: '#64748b', fontSize: '1rem' };
const statsGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '30px' };
const statCard = { background: 'white', padding: '20px', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '15px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const statNum = { fontSize: '1.5rem', fontWeight: '800', display: 'block' };
const statLabel = { margin: 0, fontSize: '0.85rem', color: '#64748b', fontWeight: '500' };
const searchBarContainer = { position: 'relative', marginBottom: '25px' };
const searchIcon = { position: 'absolute', left: '15px', top: '50%', transform: 'translateY(-50%)' };
const searchInput = { width: '100%', padding: '15px 15px 15px 45px', borderRadius: '14px', border: '1.5px solid #e2e8f0', outline: 'none', transition: '0.2s', fontSize: '1rem' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', borderRadius: '20px', border: '1px solid #f1f5f9', padding: '20px', transition: 'transform 0.2s, box-shadow 0.2s', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', cursor: 'default' };
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
